using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_87380468087d42c2aa5f68d220cab394.Auth;

public class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _authState = Task.FromResult(
        new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(
            new[]
            {
                new Claim(ClaimTypes.Name, "bob@example.com"),
                new Claim(ClaimTypes.Email, "bob@example.com"),
                new Claim(ClaimTypes.Role, "User"),
                new Claim(ClaimTypes.Role, "Editor"),
            },
            authenticationType: "Hardcoded"))));

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_87380468087d42c2aa5f68d220cab394.Auth;

/// <summary>
/// Subscribes to the server-side <see cref="AuthenticationStateProvider"/> and persists
/// the user's claims into <see cref="PersistentComponentState"/> so the WebAssembly
/// client can reconstruct the identity after it takes over.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly AuthenticationStateProvider _authProvider;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        AuthenticationStateProvider authProvider)
    {
        _persistentState = persistentState;
        _authProvider = authProvider;

        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authStateTask = authenticationStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await (_authStateTask ?? _authProvider.GetAuthenticationStateAsync());
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var claims = principal.Claims.Select(c => new ClaimData(c.Type, c.Value)).ToList();
            _persistentState.PersistAsJson(nameof(ClaimData), claims);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

public record ClaimData(string Type, string Value);

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_87380468087d42c2aa5f68d220cab394.Client.Auth;

/// <summary>
/// Client-side provider that reads the persisted claims from
/// <see cref="PersistentComponentState"/> (serialised by the server)
/// and reconstructs the <see cref="ClaimsPrincipal"/>.
/// </summary>
public class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<List<ClaimData>>(nameof(ClaimData), out var claims)
            && claims is { Count: > 0 })
        {
            var identity = new ClaimsIdentity(
                claims.Select(c => new Claim(c.Type, c.Value)),
                authenticationType: "Persisted");

            _authStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

public record ClaimData(string Type, string Value);

@page "/profile"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h3>Roles</h3>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not authenticated.</p>
    </NotAuthorized>
</AuthorizeView>

